-- =====================================================
-- SCRIPT PARA CARGAR DATOS CIE-10 CON INSERTs EN LOTES
-- =====================================================
-- Base de datos: PostgreSQL con Prisma
-- Autor: Asistente IA
-- Fecha: 2026-05-25
-- Impacto: Tabla cie10
-- =====================================================
-- NOTA: Este script funciona con Prisma:
-- Comando: npx prisma db execute --file prisma/sql/load_cie10.sql
-- =====================================================

-- Iniciar transacción
BEGIN;

-- Limpiar datos existentes antes de cargar nuevos datos
TRUNCATE TABLE cie10 RESTART IDENTITY CASCADE;

-- Lote 1 (registros 1-500)

-- Lote 2 (registros 501-1000)

-- Lote 3 (registros 1001-1500)

-- Lote 4 (registros 1501-2000)

-- Lote 5 (registros 2001-2500)

-- Lote 6 (registros 2501-3000)

-- Lote 7 (registros 3001-3500)

-- Lote 8 (registros 3501-4000)

-- Lote 9 (registros 4001-4500)

-- Lote 10 (registros 4501-5000)

-- Lote 11 (registros 5001-5500)

-- Lote 12 (registros 5501-6000)

-- Lote 13 (registros 6001-6500)

-- Lote 14 (registros 6501-7000)

-- Lote 15 (registros 7001-7500)

-- Lote 16 (registros 7501-8000)

-- Lote 17 (registros 8001-8500)

-- Lote 18 (registros 8501-9000)

-- Lote 19 (registros 9001-9500)

-- Lote 20 (registros 9501-10000)

-- Lote 21 (registros 10001-10500)

-- Lote 22 (registros 10501-11000)

-- Lote 23 (registros 11001-11500)

-- Lote 24 (registros 11501-12000)

-- Lote 25 (registros 12001-12500)

-- Lote 26 (registros 12501-12634)

-- Confirmar transacción
COMMIT;

-- =====================================================
-- VERIFICACIÓN
-- =====================================================
-- Contar registros cargados
SELECT COUNT(*) as total_registros FROM cie10;

-- Mostrar primeros 10 registros
SELECT * FROM cie10 ORDER BY codigo LIMIT 10;

-- Verificar si hay códigos duplicados
SELECT codigo, COUNT(*) as conteo
FROM cie10
GROUP BY codigo
HAVING COUNT(*) > 1;
